package com.ecoPedal.backend.repository;import com.ecoPedal.backend.entity.Participation;import com.ecoPedal.backend.entity.enums.StatutParticipation;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.util.*;import java.util.Optional;@Repositorypublic interface ParticipationRepository extends JpaRepository<Participation, Long> {    List<Participation> findByUtilisateurId(Long utilisateurId);    List<Participation> findByDefiId(Long defiId);    Optional<Participation> findByUtilisateurIdAndDefiId(Long utilisateurId, Long defiId);    boolean existsByUtilisateurIdAndDefiId(Long utilisateurId, Long defiId);    List<Participation> findByUtilisateurIdOrderByDateInscriptionDesc(Long utilisateurId);    List<Participation> findByStatut(StatutParticipation statut);}